import React, { useState } from 'react';

const App = () => {
  const [theme, setTheme] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(null);

  const toggleTheme = () => setTheme(!theme);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!username || !password || password.length < 8) {
      setError('Please fill in all fields and password must be at least 8 characters long');
    } else {
      setError(null);
      console.log('Username:', username);
      console.log('Password:', password);
    }
  };

  return (
    <div className={`min-h-screen ${theme ? 'bg-[#090a0f]' : 'bg-white'} text-${theme ? '#B7D7CD' : '#C06C88'} p-4 flex items-center justify-center`}>

      <div className='bg-[#C06C88] p-4 rounded-lg w-96'>

        <h2 className='text-[#B7D7CD] font-bold text-2xl mb-4'>Secure Access Control Panel</h2>

        <form onSubmit={handleSubmit}>

          <div className='mb-4'>

            <label className='text-[#B7D7CD] block mb-2'>Username:</label>

            <input type='text' value={username} onChange={(e) => setUsername(e.target.value)} className='w-full p-2 border border-gray-400 rounded-md'/></div>

          <div className='mb-4'>

            <label className='text-[#B7D7CD] block mb-2'>Password:</label>

            <input type='password' value={password} onChange={(e) => setPassword(e.target.value)} className='w-full p-2 border border-gray-400 rounded-md'/></div>

          <button type='submit' className='bg-[#B7D7CD] py-2 px-4 rounded-md text-[#090a0f] hover:bg-opacity-90'>Login</button>

          {error && <p className='text-[#C06C88] mt-2'>{error}</p>}

        </form>
        <button className='bg-[#B7D7CD] py-2 px-4 rounded-md text-[#090a0f] hover:bg-opacity-90 ml-2' onClick={toggleTheme}>{theme ? 'Light' : 'Dark'}</button>
        </div>
      </div>
  );
};

export default App;
